1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSED_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const BLOCK_OF_THREE_BASE_PREMIUM = 60;
7	const LOYALTY_DISCOUNT_RATE = 0.2;
8	const LOYALTY_DISCOUNT_THRESHOLD_YEARS = 2;
9	const FOLLOWUP_DISCOUNT_RATE = 0.15;
10	
11	const BASE_PREMIUMS: Record<string, number> = {
12	  sword: 100,
13	  amulet: 60,
14	  staff: 80,
15	  potion: 40,
16	  rune: 25,
17	  moonstone: 25,
18	};
19	
20	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
21	type QuoteStep = { op: "quote"; items: Item[] };
22	type Damage = { itemType: string; amount: number };
23	type Incident = { cause: string; damages: Damage[] };
24	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
25	type Step = QuoteStep | ClaimStep;
26	type Customer = { yearsWithMHPCO: number };
27	type Scenario = { customer: Customer; steps: Step[] };
28	
29	const quoteResult = (premiums: number[]) => ({ results: premiums.map((premium) => ({ premium })) });
30	
31	const claimResult = () => ({ payout: 400, remainingCap: 1600 });
32	
33	const sum = (numbers: number[]): number =>
34	  numbers.reduce((total, n) => total + n, 0);
35	
36	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type];
37	
38	const isBlockOfThreeAlike = (items: Item[]): boolean =>
39	  items.length === 3 && items.every((item) => item.type === items[0].type);
40	
41	const groupByType = (items: Item[]): Item[][] => {
42	  const groups: Record<string, Item[]> = {};
43	  for (const item of items) {
44	    (groups[item.type] ||= []).push(item);
45	  }
46	  return Object.values(groups);
47	};
48	
49	const groupBasePremium = (group: Item[]): number =>
50	  isBlockOfThreeAlike(group)
51	    ? BLOCK_OF_THREE_BASE_PREMIUM
52	    : sum(group.map(itemBasePremium));
53	
54	const itemsBasePremium = (items: Item[]): number =>
55	  sum(groupByType(items).map(groupBasePremium));
56	
57	const rateIfApplies = (amount: number, applies: boolean, rate: number): number =>
58	  applies ? amount * rate : 0;
59	
60	const cursedSurcharge = (item: Item): number =>
61	  rateIfApplies(itemBasePremium(item), item.cursed === true, CURSED_SURCHARGE_RATE);
62	
63	const highEnchantmentSurcharge = (item: Item): number =>
64	  rateIfApplies(
65	    itemBasePremium(item),
66	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
67	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
68	  );
69	
70	const itemSurchargesTotal = (items: Item[]): number =>
71	  sum(items.map((item) => cursedSurcharge(item) + highEnchantmentSurcharge(item)));
72	
73	const firstInsuranceSurcharge = (basePremium: number): number =>
74	  basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
75	
76	const loyaltyDiscount = (basePremium: number, customer: Customer): number =>
77	  rateIfApplies(
78	    basePremium,
79	    customer.yearsWithMHPCO >= LOYALTY_DISCOUNT_THRESHOLD_YEARS,
80	    LOYALTY_DISCOUNT_RATE,
81	  );
82	
83	const followupDiscount = (basePremium: number, quoteIndex: number): number =>
84	  rateIfApplies(basePremium, quoteIndex >= 1, FOLLOWUP_DISCOUNT_RATE);
85	
86	const quotePremiumFor = (items: Item[], customer: Customer, quoteIndex: number): number => {
87	  const policyBase = itemsBasePremium(items);
88	  return Math.ceil(
89	    policyBase +
90	      itemSurchargesTotal(items) +
91	      firstInsuranceSurcharge(policyBase) -
92	      loyaltyDiscount(policyBase, customer) -
93	      followupDiscount(policyBase, quoteIndex) +
94	      PROCESSING_FEE,
95	  );
96	};
97	
98	export const runScenario = (input: Scenario): unknown => {
99	  const results: unknown[] = [];
100	  let quoteIndex = 0;
101	  for (const step of input.steps) {
102	    if (step.op === "quote") {
103	      results.push({ premium: quotePremiumFor(step.items, input.customer, quoteIndex) });
104	      quoteIndex += 1;
105	    } else {
106	      results.push(claimResult());
107	    }
108	  }
109	  return { results };
110	};
